import{_ as o,o as e,c as d,ae as n}from"./chunks/framework.BIONGpTb.js";const u=JSON.parse('{"title":"Contributions","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/contributions.md","filePath":"concepts/contributions.md"}'),a={name:"concepts/contributions.md"};function r(c,t,i,s,l,b){return e(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="contributions" tabindex="-1">Contributions <a class="header-anchor" href="#contributions" aria-label="Permalink to &quot;Contributions&quot;">​</a></h1><p><strong>Contributions</strong> are declarative UI: tabs, toolbar buttons, HTML blocks, and icons. They are registered with <code>contributionRegistry.registerContribution(target, contribution)</code>.</p><h2 id="targets" tabindex="-1">Targets <a class="header-anchor" href="#targets" aria-label="Permalink to &quot;Targets&quot;">​</a></h2><p>Contribution targets define where UI appears:</p><table tabindex="0"><thead><tr><th>Constant</th><th>Role</th></tr></thead><tbody><tr><td><code>SIDEBAR_MAIN</code></td><td>Main sidebar (e.g. file tree).</td></tr><tr><td><code>SIDEBAR_MAIN_BOTTOM</code></td><td>Bottom of main sidebar.</td></tr><tr><td><code>SIDEBAR_AUXILIARY</code></td><td>Secondary sidebar.</td></tr><tr><td><code>EDITOR_AREA_MAIN</code></td><td>Editor area.</td></tr><tr><td><code>PANEL_BOTTOM</code></td><td>Bottom panel.</td></tr><tr><td><code>TOOLBAR_MAIN</code></td><td>Main toolbar.</td></tr><tr><td><code>TOOLBAR_MAIN_RIGHT</code>, <code>TOOLBAR_MAIN_CENTER</code></td><td>Main toolbar slots.</td></tr><tr><td><code>TOOLBAR_BOTTOM</code>, <code>TOOLBAR_BOTTOM_END</code>, <code>TOOLBAR_BOTTOM_CENTER</code></td><td>Bottom toolbar.</td></tr><tr><td><code>SYSTEM_LAYOUTS</code></td><td>Layout contributions (id, name, component, optional onShow). See <a href="/docs/concepts/apps.html#layouts">Apps</a>.</td></tr><tr><td><code>SYSTEM_LANGUAGE_BUNDLES</code></td><td>i18n language bundles (extensions).</td></tr></tbody></table><p>Import these from <code>@eclipse-lyra/core</code>.</p><h2 id="contribution-types" tabindex="-1">Contribution types <a class="header-anchor" href="#contribution-types" aria-label="Permalink to &quot;Contribution types&quot;">​</a></h2><ul><li><strong>CommandContribution</strong> — <code>command</code>, <code>label</code>, <code>icon</code>, optional <code>params</code>, <code>showLabel</code>, <code>disabled</code>. Used for toolbar buttons and menu items.</li><li><strong>TabContribution</strong> — <code>name</code>, optional <code>editorId</code>, <code>closable</code>, <code>noOverflow</code>, <code>component</code> (function returning a Lit template). Used for sidebar and editor area tabs.</li><li><strong>HTMLContribution</strong> — <code>component</code> (string or function returning a Lit <code>TemplateResult</code>). Raw HTML or template in a slot.</li><li><strong>LayoutContribution</strong> — For <code>SYSTEM_LAYOUTS</code>: <code>id</code>, <code>name</code>, <code>component</code> (Lit template), optional <code>onShow</code>. Defines a layout shell; the app root is the chosen layout&#39;s component.</li><li><strong>IconContribution</strong> — <code>mappings</code> (map of icon keys to identifiers), optional <code>priority</code>.</li></ul><p>All contributions can include <code>target</code>, <code>label</code>, <code>icon</code>, <code>slot</code> from the base <code>Contribution</code> interface where applicable.</p><p>See <a href="/docs/guide/add-sidebar-tab.html">Add a sidebar tab</a> and <a href="/docs/guide/add-command-toolbar.html">Add a command and toolbar button</a>.</p>',10)])])}const m=o(a,[["render",r]]);export{u as __pageData,m as default};
